            maxTime = edge[2]
        }
    }
    var left = 0
    var right = maxTime
    var answer = maxTime
    while left <= right {
        let mid = (left + right) / 2
        if check(n: Int(n), edges: edges, t: mid, k: k) {
            answer = mid
            right = mid - 1
        } else {
            left = mid + 1
        }
    }
    return Int64(answer)
}

func check(n: Int, edges: Array<Array<Int64>>, t: Int64, k: Int64) -> Bool {
    let uf = UnionFind(n: n)
    var count = n
    for edge in edges {
